{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以' (can/may) to politely ask for permission or request an action. This is a standard polite form in Taiwan.",
      "title": "Polite Request with 可以",
      "meaning": "May I [action] [object]?",
      "when_to_use": ["When ordering food or drinks at a café", "When asking for an item in a shop", "When requesting a service"],
      "when_not_to_use": ["When making a direct command", "When speaking to close friends informally"],
      "pragmatic_notes": "In Taiwan, using '可以' is very common and polite. It's softer than '我要' (I want). Often combined with '麻煩' for extra politeness.",
      "word_order_notes": "The structure is: 可以 + verb + object + 嗎. The verb must come before the object.",
      "english_contrast": "English uses 'Can I have...' or 'May I...'. Chinese uses '可以' at the beginning, not at the end.",
      "korean_contrast": "Korean uses '~을/를 주세요' or '~해도 돼요?'. Chinese '可以...嗎' is similar to '~해도 될까요?'.",
      "negative_examples": [
        {
          "text": "可以嗎咖啡喝？",
          "error": "Word order is wrong. The verb '喝' must come before the object '咖啡'."
        },
        {
          "text": "可以咖啡喝嗎？",
          "error": "The object '咖啡' should come after the verb '喝', not before."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以嗎咖啡喝？",
          "error": "Word order is wrong. The verb '喝' must come before the object '咖啡'."
        },
        {
          "text": "可以咖啡喝嗎？",
          "error": "The object '咖啡' should come after the verb '喝', not before."
        }
      ],
      "transformation_drills": ["Change '我要一杯咖啡' to '可以給我一杯咖啡嗎？'", "Change '給我水' to '可以給我水嗎？'"],
      "production_drills": ["Ask for a cup of tea politely using 可以", "Ask to see a menu using 可以"],
      "common_error_patterns": ["Placing object before verb", "Omitting 嗎 at the end"],
      "repair_feedback": {
        "word_order": "Remember: 可以 + verb + object + 嗎. The verb comes right after 可以.",
        "politeness": "Using 可以...嗎 is polite. For more politeness, add 麻煩 at the beginning.",
        "vocabulary": "Use appropriate verbs like 給, 喝, 吃, 看, 試."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' (would like) to express a desire for an object politely. It's softer than '要' (want).",
      "title": "Expressing Desire with 想要",
      "meaning": "I would like [object]",
      "when_to_use": ["When ordering food or drinks", "When stating what you want in a shop", "When making a polite request for an item"],
      "when_not_to_use": ["When asking for permission to do an action", "When making a direct command"],
      "pragmatic_notes": "In Taiwan, '想要' is very common in cafés and shops. It's polite but not overly formal. Often followed by '一杯' or '一個'.",
      "word_order_notes": "The structure is: 想要 + object. The object can be a noun phrase like '一杯咖啡'.",
      "english_contrast": "English uses 'I would like...' or 'I want...'. Chinese '想要' is similar to 'would like'.",
      "korean_contrast": "Korean uses '~을/를 원하다' or '~고 싶다'. Chinese '想要' is similar to '~을/를 원해요'.",
      "negative_examples": [
        {
          "text": "想要咖啡一杯",
          "error": "Word order is wrong. The measure word '一杯' should come before '咖啡'."
        },
        {
          "text": "想要嗎咖啡？",
          "error": "Do not add 嗎 after 想要. 想要 is a statement, not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "想要咖啡一杯",
          "error": "Word order is wrong. The measure word '一杯' should come before '咖啡'."
        },
        {
          "text": "想要嗎咖啡？",
          "error": "Do not add 嗎 after 想要. 想要 is a statement, not a question."
        }
      ],
      "transformation_drills": ["Change '我要紅茶' to '我想要紅茶'", "Change '給我水' to '我想要水'"],
      "production_drills": ["Say you would like a cup of coffee", "Say you would like a small cup of tea"],
      "common_error_patterns": ["Placing measure word after noun", "Adding 嗎 to 想要"],
      "repair_feedback": {
        "word_order": "Remember: 想要 + measure word + noun. For example, '想要一杯咖啡'.",
        "politeness": "想要 is polite. For more politeness, add '麻煩' at the beginning.",
        "vocabulary": "Use measure words like 杯, 個, 本 correctly with nouns."
      }
    },
    {
      "pattern": "不好意思 + [request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' (excuse me / sorry) as a polite softener before making a request. It shows consideration and is very common in Taiwan.",
      "title": "Polite Softener with 不好意思",
      "meaning": "Excuse me, [request]",
      "when_to_use": ["When starting a conversation with a shop assistant", "When making a request in a café", "When asking for help or information"],
      "when_not_to_use": ["When speaking to close friends", "When the request is very casual"],
      "pragmatic_notes": "In Taiwan, '不好意思' is used more often than '對不起' for polite requests. It softens the request and shows humility.",
      "word_order_notes": "Place '不好意思' at the beginning of the sentence, followed by the request. The request can be a full sentence.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry' before a request. Chinese '不好意思' serves the same function.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다'. Chinese '不好意思' is similar to '죄송합니다' but less formal.",
      "negative_examples": [
        {
          "text": "不好意思嗎一杯咖啡？",
          "error": "Do not add 嗎 after 不好意思. 不好意思 is a softener, not a question."
        },
        {
          "text": "一杯咖啡不好意思",
          "error": "不好意思 should come at the beginning, not at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思嗎一杯咖啡？",
          "error": "Do not add 嗎 after 不好意思. 不好意思 is a softener, not a question."
        },
        {
          "text": "一杯咖啡不好意思",
          "error": "不好意思 should come at the beginning, not at the end."
        }
      ],
      "transformation_drills": ["Add 不好意思 to '可以給我一杯水嗎？'", "Add 不好意思 to '我想要一杯紅茶'"],
      "production_drills": ["Politely ask for a menu using 不好意思", "Politely ask for the price using 不好意思"],
      "common_error_patterns": ["Placing 不好意思 at the end", "Adding 嗎 after 不好意思"],
      "repair_feedback": {
        "word_order": "Remember: 不好意思 comes at the beginning of the request sentence.",
        "politeness": "不好意思 is very polite. Use it to start any request in a shop or café.",
        "vocabulary": "Combine 不好意思 with other polite phrases like 可以 or 想要."
      }
    }
  ]
}
